from flask import Flask, jsonify, request
from flask_sqlalchemy import SQLAlchemy
from datetime import datetime, timedelta

app = Flask(__name__)
app.config['SQLALCHEMY_DATABASE_URI'] = 'sqlite:///todo.db'
db = SQLAlchemy(app)

class TodoList(db.Model):
    id = db.Column(db.Integer, primary_key=True)
    title = db.Column(db.String(100), nullable=False)
    items = db.relationship('TodoItem', backref='todolist', lazy=True)

class TodoItem(db.Model):
    id = db.Column(db.Integer, primary_key=True)
    title = db.Column(db.String(100), nullable=False)
    due_date = db.Column(db.DateTime, nullable=True)
    completed = db.Column(db.Boolean, default=False)
    list_id = db.Column(db.Integer, db.ForeignKey('todo_list.id'), nullable=False)

@app.route('/todolists', methods=['POST'])
def create_todo_list():
    data = request.json
    new_list = TodoList(title=data['title'])
    db.session.add(new_list)
    db.session.commit()
    return jsonify({'id': new_list.id, 'title': new_list.title}), 201

@app.route('/todolists/<int:list_id>', methods=['GET'])
def get_todo_list(list_id):
    todo_list = TodoList.query.get_or_404(list_id)
    return jsonify({'id': todo_list.id, 'title': todo_list.title, 'items': [{'id': item.id, 'title': item.title, 'due_date': item.due_date, 'completed': item.completed} for item in todo_list.items]})

@app.route('/todolists/<int:list_id>', methods=['PUT'])
def update_todo_list(list_id):
    data = request.json
    todo_list = TodoList.query.get_or_404(list_id)
    todo_list.title = data['title']
    db.session.commit()
    return jsonify({'id': todo_list.id, 'title': todo_list.title})

@app.route('/todolists/<int:list_id>', methods=['DELETE'])
def delete_todo_list(list_id):
    todo_list = TodoList.query.get_or_404(list_id)
    db.session.delete(todo_list)
    db.session.commit()
    return jsonify({'message': 'Todo list deleted'}), 204

@app.route('/todolists/<int:list_id>/items', methods=['POST'])
def add_todo_item(list_id):
    data = request.json
    new_item = TodoItem(title=data['title'], due_date=data.get('due_date'), list_id=list_id)
    db.session.add(new_item)
    db.session.commit()
    return jsonify({'id': new_item.id, 'title': new_item.title}), 201

@app.route('/todolists/<int:list_id>/items/<int:item_id>', methods=['PUT'])
def update_todo_item(list_id, item_id):
    data = request.json
    todo_item = TodoItem.query.get_or_404(item_id)
    todo_item.title = data['title']
    todo_item.due_date = data.get('due_date')
    todo_item.completed = data.get('completed', todo_item.completed)
    db.session.commit()
    return jsonify({'id': todo_item.id, 'title': todo_item.title})

@app.route('/todolists/<int:list_id>/items/<int:item_id>', methods=['DELETE'])
def delete_todo_item(list_id, item_id):
    todo_item = TodoItem.query.get_or_404(item_id)
    db.session.delete(todo_item)
    db.session.commit()
    return jsonify({'message': 'Todo item deleted'}), 204

@app.route('/todolists/<int:list_id>/progress', methods=['GET'])
def get_progress(list_id):
    todo_list = TodoList.query.get_or_404(list_id)
    total_items = len(todo_list.items)
    completed_items = sum(item.completed for item in todo_list.items)
    progress = (completed_items / total_items * 100) if total_items > 0 else 0
    return jsonify({'list_id': todo_list.id, 'progress': progress})

@app.route('/todolists/<int:list_id>/reminders', methods=['GET'])
def get_reminders(list_id):
    due_items = TodoItem.query.filter(TodoItem.list_id == list_id, TodoItem.due_date <= datetime.now(), TodoItem.completed == False).all()
    reminders = [{'id': item.id, 'title': item.title, 'due_date': item.due_date} for item in due_items]
    return jsonify({'reminders': reminders})

if __name__ == '__main__':
    db.create_all()
    app.run(debug=True)

