    todo_list = TodoList.query.get_or_404(list_id)
    todo_list.title = data['title']
    db.session.commit()
    return jsonify({'id': todo_list.id, 'title': todo_list.title})

@app.route('/lists/<int:list_id>', methods=['DELETE'])
