    todo_list = TodoList.query.get_or_404(list_id)
    db.session.delete(todo_list)
    db.session.commit()
    return jsonify({'message': 'List deleted'}), 204

@app.route('/lists/<int:list_id>/items', methods=['POST'])
def create_item(list_id):
    data = request.json
    new_item = TodoItem(title=data['title'], due_date=data.get('due_date'), list_id=list_id)
    db.session.add(new_item)
    db.session.commit()
    return jsonify({'id': new_item.id, 'title': new_item.title}), 201

@app.route('/lists/<int:list_id>/items/<int:item_id>', methods=['PUT'])
def update_item(list_id, item_id):
    data = request.json
    item = TodoItem.query.get_or_404(item_id)
    item.title = data['title']
    item.due_date = data.get('due_date')
    item.completed = data.get('completed', item.completed)
    db.session.commit()
    return jsonify({'id': item.id, 'title': item.title})

@app.route('/lists/<int:list_id>/items/<int:item_id>', methods=['DELETE'])
def delete_item(list_id, item_id):
    item = TodoItem.query.get_or_404(item_id)
    db.session.delete(item)
    db.session.commit()
    return jsonify({'message': 'Item deleted'}), 204

@app.route('/lists/<int:list_id>/progress', methods=['GET'])
def get_progress(list_id):
    todo_list = TodoList.query.get_or_404(list_id)
    total_items = len(todo_list.items)
    completed_items = sum(item.completed for item in todo_list.items)
    progress = (completed_items / total_items * 100) if total_items > 0 else 0
    return jsonify({'list_id': list_id, 'progress': progress})

@app.route('/reminders', methods=['GET'])
def get_reminders():
    now = datetime.now()
    overdue_items = TodoItem.query.filter(TodoItem.due_date < now, TodoItem.completed == False).all()
    return jsonify({'overdue_items': [{'id': item.id, 'title': item.title} for item in overdue_items]})

if __name__ == '__main__':
    db.create_all()
    app.run(debug=True)

