    todos = TodoItem.query.all()
    return jsonify([{
        'id': todo.id,
        'title': todo.title,
        'description': todo.description,
        'due_date': todo.due_date.strftime('%Y-%m-%d') if todo.due_date else None,
        'completed': todo.completed
    } for todo in todos])

@app.route('/progress', methods=['GET'])
def get_progress():
    total_todos = TodoItem.query.count()
    completed_todos = TodoItem.query.filter_by(completed=True).count()
    progress = (completed_todos / total_todos * 100) if total_todos > 0 else 0
    return jsonify({'progress': progress})

@app.route('/reminders', methods=['GET'])
def get_reminders():
    today = datetime.now()
    upcoming_due = TodoItem.query.filter(TodoItem.due_date >= today, TodoItem.completed == False).all()
    overdue = TodoItem.query.filter(TodoItem.due_date < today, TodoItem.completed == False).all()
    return jsonify({
        'upcoming_due': [{
            'id': todo.id,
