app.config['SQLALCHEMY_TRACK_MODIFICATIONS'] = False
db = SQLAlchemy(app)

class Todo(db.Model):
    id = db.Column(db.Integer, primary_key=True)
    task = db.Column(db.String(200), nullable=False)
    completed = db.Column(db.Boolean, default=False)
    due_date = db.Column(db.DateTime, nullable=True)

db.create_all()

@app.route('/todos', methods=['GET'])
def get_todos():
    todos = Todo.query.all()
    return jsonify([{'id': todo.id, 'task': todo.task, 'completed': todo.completed, 'due_date': todo.due_date} for todo in todos])

@app.route('/todos', methods=['POST'])
def create_todo():
    data = request.json
    new_todo = Todo(task=data['task'], completed=False, due_date=data.get('due_date'))
    db.session.add(new_todo)
    db.session.commit()
    return jsonify({'id': new_todo.id, 'task': new_todo.task, 'completed': new_todo.completed, 'due_date': new_todo.due_date}), 201

@app.route('/todos/<int:todo_id>', methods=['PUT'])
def update_todo(todo_id):
    todo = Todo.query.get_or_404(todo_id)
    data = request.json
    todo.task = data.get('task', todo.task)
    todo.completed = data.get('completed', todo.completed)
    todo.due_date = data.get('due_date', todo.due_date)
    db.session.commit()
    return jsonify({'id': todo.id, 'task': todo.task, 'completed': todo.completed, 'due_date': todo.due_date})

@app.route('/todos/<int:todo_id>', methods=['DELETE'])
def delete_todo(todo_id):
    todo = Todo.query.get_or_404(todo_id)
    db.session.delete(todo)
    db.session.commit()
    return jsonify({'message': 'Todo deleted successfully'})

@app.route('/todos/progress', methods=['GET'])
def get_progress():
    todos = Todo.query.all()
    total = len(todos)
    completed = sum(1 for todo in todos if todo.completed)
    progress = (completed / total * 100) if total > 0 else 0
    return jsonify({'total': total, 'completed': completed, 'progress': progress})

@app.route('/todos/reminders', methods=['GET'])
def get_reminders():
    now = datetime.now()
    reminders = Todo.query.filter(Todo.due_date != None, Todo.due_date <= now + timedelta(days=1)).all()
    return jsonify([{'id': todo.id, 'task': todo.task, 'due_date': todo.due_date} for todo in reminders])

if __name__ == '__main__':
    app.run(debug=True)

from flask import Flask, jsonify, request
from flask_sqlalchemy import SQLAlchemy
from datetime import datetime, timedelta

app = Flask(__name__)
app.config['SQLALCHEMY_DATABASE_URI'] = 'sqlite:///todo.db'
app.config['SQLALCHEMY_TRACK_MODIFICATIONS'] = False
db = SQLAlchemy(app)

class Todo(db.Model):
    id = db.Column(db.Integer, primary_key=True)
    task = db.Column(db.String(200), nullable=False)
    completed = db.Column(db.Boolean, default=False)
    due_date = db.Column(db.DateTime, nullable=True)

db.create_all()

@app.route('/todos', methods=['POST'])
def create_todo():
    data = request.json
    new_todo = Todo(task=data['task'], due_date=data.get('due_date'))
    db.session.add(new_todo)
    db.session.commit()
    return jsonify({'id': new_todo.id, 'task': new_todo.task, 'due_date': new_todo.due_date}), 201

@app.route('/todos/<int:todo_id>', methods=['GET'])
def get_todo(todo_id):
    todo = Todo.query.get_or_404(todo_id)
    return jsonify({'id': todo.id, 'task': todo.task, 'completed': todo.completed, 'due_date': todo.due_date})

@app.route('/todos/<int:todo_id>', methods=['PUT'])
def update_todo(todo_id):
    data = request.json
    todo = Todo.query.get_or_404(todo_id)
    todo.task = data.get('task', todo.task)
    todo.completed = data.get('completed', todo.completed)
    todo.due_date = data.get('due_date', todo.due_date)
    db.session.commit()
    return jsonify({'id': todo.id, 'task': todo.task, 'completed': todo.completed, 'due_date': todo.due_date})

@app.route('/todos/<int:todo_id>', methods=['DELETE'])
def delete_todo(todo_id):
    todo = Todo.query.get_or_404(todo_id)
    db.session.delete(todo)
    db.session.commit()
    return jsonify({'message': 'Todo deleted successfully'}), 204

@app.route('/todos', methods=['GET'])
def get_all_todos():
    todos = Todo.query.all()
    return jsonify([{'id': todo.id, 'task': todo.task, 'completed': todo.completed, 'due_date': todo.due_date} for todo in todos])

@app.route('/progress', methods=['GET'])
def get_progress():
    todos = Todo.query.all()
    total = len(todos)
    completed = sum(1 for todo in todos if todo.completed)
    progress = (completed / total * 100) if total > 0 else 0
    return jsonify({'total_tasks': total, 'completed_tasks': completed, 'progress_percentage': progress})

@app.route('/reminders', methods=['GET'])
def get_reminders():
    now = datetime.now()
    upcoming_due_tasks = Todo.query.filter(Todo.due_date != None, Todo.due_date <= now + timedelta(days=1)).all()
    return jsonify([{'id': todo.id, 'task': todo.task, 'due_date': todo.due_date} for todo in upcoming_due_tasks])

if __name__ == '__main__':
    app.run(debug=True)
